-- Modify "production_order_items" table
ALTER TABLE "production_order_items" ADD CONSTRAINT "production_order_items_customer_gate_route" CHECK ((NOT customer_inspection_required) OR (route_code IS NOT NULL)), ADD CONSTRAINT "production_order_items_route_allowed" CHECK ((route_code IS NULL) OR ((route_code)::text = 'PLUSH_SEW_HAND_V1'::text)), ADD COLUMN "route_code" character varying NULL, ADD COLUMN "customer_inspection_required" boolean NOT NULL DEFAULT false;
-- Create index "productionorderitem_route_code" to table: "production_order_items"
