-- Create "production_order_operations" table
CREATE TABLE "production_order_operations" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "route_code" character varying NOT NULL,
  "route_version" bigint NOT NULL,
  "step_no" bigint NOT NULL,
  "operation_code" character varying NOT NULL,
  "process_code_snapshot" character varying NOT NULL,
  "process_name_snapshot" character varying NOT NULL,
  "output_code" character varying NOT NULL,
  "inhouse_allowed" boolean NOT NULL DEFAULT false,
  "outsourcing_allowed" boolean NOT NULL DEFAULT false,
  "planned_quantity" numeric(20,6) NOT NULL,
  "required_quality_gates" jsonb NOT NULL,
  "business_confirmation_code" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "production_order_id" bigint NOT NULL,
  "production_order_item_id" bigint NOT NULL,
  "process_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "production_order_operations_processes_process" FOREIGN KEY ("process_id") REFERENCES "processes" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_operations_production_order_items_operations" FOREIGN KEY ("production_order_item_id") REFERENCES "production_order_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_operations_production_orders_operations" FOREIGN KEY ("production_order_id") REFERENCES "production_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_operations_business_confirmation_scope" CHECK ((((operation_code)::text = 'PACKAGING'::text) AND ((business_confirmation_code)::text = 'PACKAGING_MATERIAL'::text)) OR (((operation_code)::text <> 'PACKAGING'::text) AND (business_confirmation_code IS NULL))),
  CONSTRAINT "production_order_operations_execution_supported" CHECK (inhouse_allowed OR outsourcing_allowed),
  CONSTRAINT "production_order_operations_operation_present" CHECK ((length(TRIM(BOTH FROM operation_code)) >= 1) AND (length(TRIM(BOTH FROM operation_code)) <= 64)),
  CONSTRAINT "production_order_operations_order_positive" CHECK (production_order_id > 0),
  CONSTRAINT "production_order_operations_output_code_present" CHECK ((length(TRIM(BOTH FROM output_code)) >= 1) AND (length(TRIM(BOTH FROM output_code)) <= 64)),
  CONSTRAINT "production_order_operations_process_name_present" CHECK ((length(TRIM(BOTH FROM process_name_snapshot)) >= 1) AND (length(TRIM(BOTH FROM process_name_snapshot)) <= 255)),
  CONSTRAINT "production_order_operations_process_positive" CHECK (process_id > 0),
  CONSTRAINT "production_order_operations_quantity_positive" CHECK (planned_quantity > (0)::numeric),
  CONSTRAINT "production_order_operations_route_fixed" CHECK (((route_code)::text = 'PLUSH_SEW_HAND_V1'::text) AND (route_version = 1)),
  CONSTRAINT "production_order_operations_route_step_fixed" CHECK (((step_no = 10) AND ((operation_code)::text = 'FABRIC_PROCESSING'::text) AND ((output_code)::text = 'CUT_PIECE'::text) AND (NOT inhouse_allowed) AND outsourcing_allowed) OR ((step_no = 20) AND ((operation_code)::text = 'SEWING'::text) AND ((output_code)::text = 'SHELL'::text) AND inhouse_allowed AND outsourcing_allowed) OR ((step_no = 30) AND ((operation_code)::text = 'HANDWORK'::text) AND ((output_code)::text = 'FINISHED_GOODS'::text) AND inhouse_allowed AND outsourcing_allowed) OR ((step_no = 40) AND ((operation_code)::text = 'PACKAGING'::text) AND ((output_code)::text = 'PACKED_GOODS'::text) AND inhouse_allowed AND (NOT outsourcing_allowed))),
  CONSTRAINT "production_order_operations_step_positive" CHECK (step_no > 0)
);
-- Create index "productionorderoperation_operation_code" to table: "production_order_operations"
CREATE INDEX "productionorderoperation_operation_code" ON "production_order_operations" ("operation_code");
-- Create index "productionorderoperation_process_id" to table: "production_order_operations"
CREATE INDEX "productionorderoperation_process_id" ON "production_order_operations" ("process_id");
-- Create index "productionorderoperation_production_order_id_step_no" to table: "production_order_operations"
CREATE INDEX "productionorderoperation_production_order_id_step_no" ON "production_order_operations" ("production_order_id", "step_no");
-- Create index "productionorderoperation_production_order_item_id_step_no" to table: "production_order_operations"
CREATE UNIQUE INDEX "productionorderoperation_production_order_item_id_step_no" ON "production_order_operations" ("production_order_item_id", "step_no");
-- Create "production_packaging_confirmations" table
CREATE TABLE "production_packaging_confirmations" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "status" character varying NOT NULL DEFAULT 'PENDING',
  "version" bigint NOT NULL DEFAULT 1,
  "packaging_version_snapshot" character varying NULL,
  "confirmed_at" timestamptz NULL,
  "confirmation_idempotency_key" character varying NULL,
  "confirmation_intent_hash" character varying NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "production_order_id" bigint NOT NULL,
  "production_order_item_id" bigint NOT NULL,
  "confirmed_by" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "production_packaging_confirmations_admin_users_confirmer" FOREIGN KEY ("confirmed_by") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_packaging_confirmations_production_order_items_packa" FOREIGN KEY ("production_order_item_id") REFERENCES "production_order_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_packaging_confirmations_production_orders_packaging_" FOREIGN KEY ("production_order_id") REFERENCES "production_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_packaging_confirmations_actor_bundle" CHECK ((((status)::text = 'PENDING'::text) AND (confirmed_by IS NULL) AND (confirmed_at IS NULL) AND (packaging_version_snapshot IS NULL) AND (confirmation_idempotency_key IS NULL) AND (confirmation_intent_hash IS NULL)) OR (((status)::text = 'CONFIRMED'::text) AND (confirmed_by IS NOT NULL) AND (confirmed_at IS NOT NULL) AND (packaging_version_snapshot IS NOT NULL) AND ((length(TRIM(BOTH FROM packaging_version_snapshot)) >= 1) AND (length(TRIM(BOTH FROM packaging_version_snapshot)) <= 128)) AND (confirmation_idempotency_key IS NOT NULL) AND ((length(TRIM(BOTH FROM confirmation_idempotency_key)) >= 1) AND (length(TRIM(BOTH FROM confirmation_idempotency_key)) <= 128)) AND (confirmation_intent_hash IS NOT NULL) AND (length((confirmation_intent_hash)::text) = 64))),
  CONSTRAINT "production_packaging_confirmations_order_positive" CHECK (production_order_id > 0),
  CONSTRAINT "production_packaging_confirmations_status_allowed" CHECK ((status)::text = ANY ((ARRAY['PENDING'::character varying, 'CONFIRMED'::character varying])::text[])),
  CONSTRAINT "production_packaging_confirmations_version_positive" CHECK (version > 0)
);
-- Create index "production_packaging_confirmations_production_order_item_id_key" to table: "production_packaging_confirmations"
CREATE UNIQUE INDEX "production_packaging_confirmations_production_order_item_id_key" ON "production_packaging_confirmations" ("production_order_item_id");
-- Create index "productionpackagingconfirmation_production_order_id_status" to table: "production_packaging_confirmations"
CREATE INDEX "productionpackagingconfirmation_production_order_id_status" ON "production_packaging_confirmations" ("production_order_id", "status");
-- Create index "productionpackagingconfirmation_production_order_item_id_confir" to table: "production_packaging_confirmations"
CREATE UNIQUE INDEX "productionpackagingconfirmation_production_order_item_id_confir" ON "production_packaging_confirmations" ("production_order_item_id", "confirmation_idempotency_key") WHERE (confirmation_idempotency_key IS NOT NULL);
-- Create "production_wip_batches" table
CREATE TABLE "production_wip_batches" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "batch_no" character varying NOT NULL,
  "flow_type" character varying NOT NULL DEFAULT 'NORMAL',
  "execution_mode" character varying NULL,
  "status" character varying NOT NULL DEFAULT 'PLANNED',
  "version" bigint NOT NULL DEFAULT 1,
  "quantity" numeric(20,6) NOT NULL,
  "rework_reason" character varying NULL,
  "started_at" timestamptz NULL,
  "completed_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "outsourcing_order_item_id" bigint NULL,
  "production_order_id" bigint NOT NULL,
  "production_order_item_id" bigint NOT NULL,
  "production_order_operation_id" bigint NOT NULL,
  "source_batch_id" bigint NULL,
  "created_by" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "production_wip_batches_admin_users_creator" FOREIGN KEY ("created_by") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_batches_outsourcing_order_items_production_wip_b" FOREIGN KEY ("outsourcing_order_item_id") REFERENCES "outsourcing_order_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_batches_production_order_items_wip_batches" FOREIGN KEY ("production_order_item_id") REFERENCES "production_order_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_batches_production_order_operations_wip_batches" FOREIGN KEY ("production_order_operation_id") REFERENCES "production_order_operations" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_batches_production_orders_wip_batches" FOREIGN KEY ("production_order_id") REFERENCES "production_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_batches_production_wip_batches_child_batches" FOREIGN KEY ("source_batch_id") REFERENCES "production_wip_batches" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_batches_execution_allowed" CHECK ((execution_mode IS NULL) OR ((execution_mode)::text = ANY ((ARRAY['IN_HOUSE'::character varying, 'OUTSOURCED'::character varying])::text[]))),
  CONSTRAINT "production_wip_batches_execution_bundle" CHECK (((execution_mode IS NULL) AND (outsourcing_order_item_id IS NULL)) OR (((execution_mode)::text = 'IN_HOUSE'::text) AND (outsourcing_order_item_id IS NULL)) OR (((execution_mode)::text = 'OUTSOURCED'::text) AND (outsourcing_order_item_id IS NOT NULL))),
  CONSTRAINT "production_wip_batches_flow_type_allowed" CHECK ((flow_type)::text = ANY ((ARRAY['NORMAL'::character varying, 'REWORK'::character varying])::text[])),
  CONSTRAINT "production_wip_batches_order_positive" CHECK (production_order_id > 0),
  CONSTRAINT "production_wip_batches_quantity_positive" CHECK (quantity > (0)::numeric),
  CONSTRAINT "production_wip_batches_rework_bundle" CHECK ((((flow_type)::text = 'NORMAL'::text) AND (rework_reason IS NULL)) OR (((flow_type)::text = 'REWORK'::text) AND (source_batch_id IS NOT NULL) AND (rework_reason IS NOT NULL) AND ((length(TRIM(BOTH FROM rework_reason)) >= 1) AND (length(TRIM(BOTH FROM rework_reason)) <= 255)))),
  CONSTRAINT "production_wip_batches_status_allowed" CHECK ((status)::text = ANY ((ARRAY['PLANNED'::character varying, 'SPLIT'::character varying, 'IN_PROGRESS'::character varying, 'OUTSOURCED'::character varying, 'WAITING_QUALITY'::character varying, 'ACCEPTED'::character varying, 'REJECTED'::character varying, 'CANCELLED'::character varying])::text[])),
  CONSTRAINT "production_wip_batches_version_positive" CHECK (version > 0)
);
-- Create index "productionwipbatch_batch_no" to table: "production_wip_batches"
CREATE UNIQUE INDEX "productionwipbatch_batch_no" ON "production_wip_batches" ("batch_no");
-- Create index "productionwipbatch_outsourcing_order_item_id" to table: "production_wip_batches"
CREATE UNIQUE INDEX "productionwipbatch_outsourcing_order_item_id" ON "production_wip_batches" ("outsourcing_order_item_id") WHERE ((outsourcing_order_item_id IS NOT NULL) AND ((status)::text <> 'CANCELLED'::text));
-- Create index "productionwipbatch_production_order_item_id_production_order_op" to table: "production_wip_batches"
CREATE INDEX "productionwipbatch_production_order_item_id_production_order_op" ON "production_wip_batches" ("production_order_item_id", "production_order_operation_id");
-- Create index "productionwipbatch_source_batch_id" to table: "production_wip_batches"
CREATE INDEX "productionwipbatch_source_batch_id" ON "production_wip_batches" ("source_batch_id");
-- Create index "productionwipbatch_status_execution_mode" to table: "production_wip_batches"
CREATE INDEX "productionwipbatch_status_execution_mode" ON "production_wip_batches" ("status", "execution_mode");
-- Create "production_wip_events" table
CREATE TABLE "production_wip_events" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "action" character varying NOT NULL,
  "from_status" character varying NULL,
  "to_status" character varying NOT NULL,
  "batch_version" bigint NOT NULL,
  "quantity" numeric(20,6) NOT NULL,
  "idempotency_key" character varying NOT NULL,
  "intent_hash" character varying NOT NULL,
  "result_contract" character varying NOT NULL,
  "mutation_result" jsonb NOT NULL,
  "reason" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "production_wip_batch_id" bigint NOT NULL,
  "actor_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "production_wip_events_admin_users_actor" FOREIGN KEY ("actor_id") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_events_production_wip_batches_events" FOREIGN KEY ("production_wip_batch_id") REFERENCES "production_wip_batches" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_wip_events_action_allowed" CHECK ((action)::text = ANY ((ARRAY['INITIALIZE'::character varying, 'SPLIT_BATCH'::character varying, 'ASSIGN_EXECUTION'::character varying, 'START_OPERATION'::character varying, 'COMPLETE_OPERATION'::character varying, 'WIP_TRANSFER'::character varying, 'OUTSOURCE_RETURN'::character varying, 'REWORK'::character varying, 'CANCEL'::character varying])::text[])),
  CONSTRAINT "production_wip_events_contract_v1" CHECK ((result_contract)::text = 'production.wip-mutation-result/v1'::text),
  CONSTRAINT "production_wip_events_hash_length" CHECK (length((intent_hash)::text) = 64),
  CONSTRAINT "production_wip_events_key_present" CHECK ((length(TRIM(BOTH FROM idempotency_key)) >= 1) AND (length(TRIM(BOTH FROM idempotency_key)) <= 128)),
  CONSTRAINT "production_wip_events_quantity_positive" CHECK (quantity > (0)::numeric),
  CONSTRAINT "production_wip_events_status_allowed" CHECK (((from_status IS NULL) OR ((from_status)::text = ANY ((ARRAY['PLANNED'::character varying, 'SPLIT'::character varying, 'IN_PROGRESS'::character varying, 'OUTSOURCED'::character varying, 'WAITING_QUALITY'::character varying, 'ACCEPTED'::character varying, 'REJECTED'::character varying, 'CANCELLED'::character varying])::text[]))) AND ((to_status)::text = ANY ((ARRAY['PLANNED'::character varying, 'SPLIT'::character varying, 'IN_PROGRESS'::character varying, 'OUTSOURCED'::character varying, 'WAITING_QUALITY'::character varying, 'ACCEPTED'::character varying, 'REJECTED'::character varying, 'CANCELLED'::character varying])::text[]))),
  CONSTRAINT "production_wip_events_version_positive" CHECK (batch_version > 0)
);
-- Create index "productionwipevent_production_wip_batch_id_actor_id_action_idem" to table: "production_wip_events"
CREATE UNIQUE INDEX "productionwipevent_production_wip_batch_id_actor_id_action_idem" ON "production_wip_events" ("production_wip_batch_id", "actor_id", "action", "idempotency_key");
-- Create index "productionwipevent_production_wip_batch_id_batch_version" to table: "production_wip_events"
CREATE UNIQUE INDEX "productionwipevent_production_wip_batch_id_batch_version" ON "production_wip_events" ("production_wip_batch_id", "batch_version");
-- Create index "productionwipevent_production_wip_batch_id_created_at" to table: "production_wip_events"
CREATE INDEX "productionwipevent_production_wip_batch_id_created_at" ON "production_wip_events" ("production_wip_batch_id", "created_at");
-- Modify "quality_inspections" table
ALTER TABLE "quality_inspections" ADD CONSTRAINT "quality_inspections_production_gate_allowed" CHECK ((gate_code IS NULL) OR ((gate_code)::text = ANY ((ARRAY['CUT_PIECE'::character varying, 'SHELL'::character varying, 'FINISHED_GOODS'::character varying, 'NEEDLE'::character varying, 'SAMPLING'::character varying, 'CUSTOMER_ACCEPTANCE'::character varying])::text[]))), ADD CONSTRAINT "quality_inspections_source_shape" CHECK (((production_wip_batch_id IS NULL) AND (gate_code IS NULL) AND (inventory_lot_id IS NOT NULL) AND (warehouse_id IS NOT NULL)) OR ((production_wip_batch_id IS NOT NULL) AND (gate_code IS NOT NULL) AND (source_type IS NOT NULL) AND ((source_type)::text = 'PRODUCTION_WIP'::text) AND (source_id IS NOT NULL) AND (source_id = production_wip_batch_id) AND (inspection_type IS NOT NULL) AND ((inspection_type)::text = 'PRODUCTION_STAGE'::text) AND (subject_type IS NOT NULL) AND ((subject_type)::text = 'WIP'::text) AND (subject_id IS NOT NULL) AND (subject_id = production_wip_batch_id) AND (inventory_lot_id IS NULL) AND (warehouse_id IS NULL) AND (purchase_receipt_id IS NULL) AND (purchase_receipt_item_id IS NULL) AND (material_id IS NULL))), ALTER COLUMN "inventory_lot_id" DROP NOT NULL, ALTER COLUMN "warehouse_id" DROP NOT NULL, ADD COLUMN "gate_code" character varying NULL, ADD COLUMN "production_wip_batch_id" bigint NULL, ADD CONSTRAINT "quality_inspections_production_wip_batches_quality_inspections" FOREIGN KEY ("production_wip_batch_id") REFERENCES "production_wip_batches" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION;
-- Create index "qualityinspection_production_wip_batch_id_gate_code" to table: "quality_inspections"
CREATE INDEX "qualityinspection_production_wip_batch_id_gate_code" ON "quality_inspections" ("production_wip_batch_id", "gate_code");
-- Create index "qualityinspection_wip_batch_gate_active" to table: "quality_inspections"
CREATE UNIQUE INDEX "qualityinspection_wip_batch_gate_active" ON "quality_inspections" ("production_wip_batch_id", "gate_code") WHERE ((production_wip_batch_id IS NOT NULL) AND (gate_code IS NOT NULL) AND ((status)::text <> 'CANCELLED'::text));
